{
  "family": "Ritter Reaction",
  "candidate": {
    "substrate_smiles": [
      "CC(C)(C)O",
      "CC#N"
    ],
    "product_smiles": [
      "CC(=O)NC(C)(C)C"
    ],
    "optional_reagent_smiles": [
      "O=S(=O)(O)O"
    ],
    "rationale": "This reaction is a classic textbook example of the Ritter reaction. Tert-butanol is protonated by sulfuric acid and loses water to form the stable tert-butyl carbocation. This carbocation is then trapped by the nucleophilic nitrogen of acetonitrile, forming a nitrilium ion intermediate. Subsequent hydrolysis yields N-tert-butylacetamide. All reactants and products are simple, acyclic, and RDKit-parseable, clearly illustrating the core transformation of an alcohol and a nitrile into an N-substituted amide.",
    "collision_avoidance_note": "This example uses simple, acyclic aliphatic substrates (tert-butanol and acetonitrile) to avoid overlap with reactions involving aromatic rings (e.g., Friedel-Crafts), complex rearrangements, or other functional groups that might trigger different named reaction classifiers. The core transformation is clearly the formation of an amide from a carbocation source and a nitrile, which is the defining feature of the Ritter reaction."
  }
}
